final:
module Counter_8_load(
   input                clk,
   input                rst,
   input                load,
   input  [7:0]         load_val,
   output reg [7:0]     obf_Q  
);
    always@(posedge clk)begin
        if(rst) obf_Q <= 8'd0;
        else if(load) obf_Q <= load_val;
        else obf_Q <= obf_Q + 1;
    end
endmodule
